template:
struct Book {
    title: String,
    author: String,
    pages: u32,
    year: u32,
}

fn create_book(title: String, author: String, pages: u32) -> Book {
    Book {
        title,
        author,
        pages,
        [[SLOT year_explicit]]
    }
}

fn create_book_with_year(title: String, author: String, pages: u32, year: u32) -> Book {
    Book {
        title,
        author,
        pages,
        year,
    }
}

fn get_title(book: &Book) -> &String {
    &book.title
}

fn main() {
    let book = create_book_with_year(
        String::from("The Rust Programming Language"),
        String::from("Steve Klabnik"),
        552,
        [[SLOT year_arg]]
    );
    println!("Title: {} ({})", get_title(&book), book.year);
}
